// ObtГ©m o primeiro item do fluxo
const item = $input.first();

// Garante que hГЎ dados na entrada
if (!item || !item.json || !item.json.text) {
  throw new Error("A chave 'text' nГЈo foi encontrada no JSON de entrada.");
}

// Processa o texto removendo todas as quebras de linha, emojis e caracteres especiais
const textoEntrada = item.json.text; // Usa a chave correta para pegar o texto de entrada

// Remove quebras de linha (\n)
let textoProcessado = textoEntrada.replace(/\n/g, "");

// Remove emojis
textoProcessado = textoProcessado.replace(
  /[\u{1F600}-\u{1F64F}]|[\u{1F300}-\u{1F5FF}]|[\u{1F680}-\u{1F6FF}]|[\u{1F700}-\u{1F77F}]|[\u{1F780}-\u{1F7FF}]|[\u{1F800}-\u{1F8FF}]|[\u{1F900}-\u{1F9FF}]|[\u{1FA00}-\u{1FA6F}]|[\u{1FA70}-\u{1FAFF}]|[\u{2600}-\u{26FF}]|[\u{2700}-\u{27BF}]|[\u{FE00}-\u{FE0F}]|[\u{1F1E0}-\u{1F1FF}]/gu,
  ""
);

// Remove caracteres especiais, mantendo apenas letras, nГәmeros e espaГ§os
textoProcessado = textoProcessado.replace(/[^a-zA-Z0-9ГҖ-Гҝ\s]/g, "");

// Retorna o resultado
return {
  textoOriginal: textoEntrada,
  textoSemQuebrasNemEmojisNemEspeciais: textoProcessado,
};

// рҹ”ҙ TRATAMENTO DE ERRO DO AGENTE
if (items[0].json.error) {
  return [{
    json: {
      resposta: "Opa, parece que algo deu errado e nГЈo consegui processar a sua mensagem. Poderia me explicar melhor?",
      url_img: null,
      tipo: "erro_agente"
    }
  }];
}

let final;
try {
  let rawOutput = items[0].json.output;

  // =========================
  // рҹ§  NORMALIZA ENTRADA
  // =========================
  if (typeof rawOutput !== 'string') {
    rawOutput = JSON.stringify(rawOutput);
  }
  rawOutput = rawOutput
    .replace(/```json/g, '')
    .replace(/```/g, '')
    .trim();

  // =========================
  // рҹ§  DESERIALIZA JSON MULTI-CAMADA
  // =========================
  for (let i = 0; i < 5; i++) {
    try {
      const parsed = JSON.parse(rawOutput);
      if (typeof parsed === 'string') {
        rawOutput = parsed;
      } else {
        rawOutput = parsed;
        break;
      }
    } catch {
      break;
    }
  }

  // =========================
  // рҹҹў CASO: JГҒ Гү OBJETO JSON COM resposta + url_img
  // =========================
  if (typeof rawOutput === 'object' && rawOutput !== null) {
    final = {
      resposta: rawOutput.resposta || null,
      url_img: rawOutput.url_img || null,
      tipo: "json_limpo"
    };
  } else {
    let resposta = String(rawOutput);
    let url_img = null;

    // =========================
    // рҹ”Қ ENCONTRA A URL DO IMAGE-CHARTS (QUALQUER FORMATO)
    // EstratГ©gia: achar onde comeГ§a a URL, pegar tudo atГ© o Гәltimo %7D
    // Isso evita problemas com parГӘnteses dentro da URL (rgba, etc.)
    // =========================
    const URL_MARKER = 'https://image-charts.com';
    const urlStart = resposta.indexOf(URL_MARKER);

    if (urlStart !== -1) {
      // Pega a string inteira a partir do inГӯcio da URL
      const fromUrl = resposta.substring(urlStart);

      // Encontra o Гәltimo %7D (fecha o JSON raiz da URL encoded)
      const lastIdx = fromUrl.lastIndexOf('%7D');

      if (lastIdx !== -1) {
        url_img = fromUrl.substring(0, lastIdx + 3);
      } else {
        // Fallback: pega atГ© o primeiro espaГ§o ou quebra de linha
        const endMatch = fromUrl.match(/[\s\n]/);
        url_img = endMatch ? fromUrl.substring(0, endMatch.index) : fromUrl;
      }

      // Remove da resposta: tudo a partir do inГӯcio do bloco markdown
      // (que pode ser "![texto](" antes da URL) ou da prГіpria URL
      const mdBlockStart = resposta.lastIndexOf('![', urlStart);
      const cutFrom = mdBlockStart !== -1 && mdBlockStart > urlStart - 200
        ? mdBlockStart
        : urlStart;

      resposta = resposta.substring(0, cutFrom).trim();
    }

    // =========================
    // рҹ§№ LIMPEZA FINAL DA RESPOSTA
    // =========================
    resposta = resposta
      .replace(/\)\s*$/, '')       // remove ) solto no final
      .replace(/\s{3,}/g, '\n\n') // colapsa espaГ§os excessivos
      .trim();

    final = {
      resposta,
      url_img,
      tipo: "texto_processado"
    };
  }
} catch (error) {
  console.log('вқҢ Erro:', error);
  final = {
    resposta: "Erro ao processar resposta",
    url_img: null,
    tipo: "erro_parse",
    detalhes: error.message
  };
}

// =========================
// рҹ”’ GARANTE FORMATO FINAL
// =========================
final = {
  resposta: final.resposta || null,
  url_img: final.url_img || null,
  tipo: final.tipo || "fallback"
};

return [{ json: final }];

